#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e5+5;
const int M = 170;
const int K = 350;
int n,Q,a[N],B,S,V,L[N],R[N],tot,tS;
int cnt[M][N],sumc[M][N],sums[M][K];
int rt[M][N],fa[N];
int tc[N],ts[N];
inline int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
inline int bel(int x){return (x-1)/B+1;}
inline int bsl(int x){return (x-1)/S+1;}
inline int FF(int u){return (fa[u]==u?u:fa[u]=FF(fa[u]));}
inline void recon(int b,int l,int r,int x,int y){
    //b 是块的编号，[l,r] 是范围，把所有 x 改成 y
    int l0=L[b],r0=R[b],top=0;
    rt[b][x]=0,rt[b][y]=0;//清零
    for(int i=l0;i<=r0;i++){
        a[i]=a[FF(i)];//赋值
        if(a[i]==x||a[i]==y)tc[++top]=i;
        //涉及到的位置进行暂存
    }
    int cx=0;
    for(int i=l;i<=r;i++)
        if(a[i]==x)cx++,a[i]=y;//记录 x 个数并修改
    for(int i=1;i<=top;i++)
        fa[tc[i]]=tc[i];//初始化，重置
    for(int i=1;i<=top;i++){
        int p=tc[i];
        if(!rt[b][a[p]])rt[b][a[p]]=p;
        //还没有根，那就先自己成为根
        else fa[p]=rt[b][a[p]];//否则向根连边
    }
    cnt[b][x]-=cx,cnt[b][y]+=cx;//更新
    for(int i=b;i<=tot;i++){
        sumc[i][x]-=cx,sumc[i][y]+=cx;//更新
        sums[i][bsl(x)]-=cx,sums[i][bsl(y)]+=cx;//更新
    }
    for(int i=1;i<=top;i++)tc[i]=0;
    return;
}
int main(){
    n=read(),Q=read();
    B=600,S=317;//设置块长
    V=100000;//值域
    for(int i=1;i<=n;i++)a[i]=read(),fa[i]=i;//读入
    tot=(n-1)/B+1;//块的个数
    tS=(V-1)/S+1;//值域块的个数
    for(int i=1;i<=tot;i++)
        L[i]=(i-1)*B+1,R[i]=min(n,i*B);
        //每个块的范围，注意不要越界（超过 n）
    for(int x=1;x<=tot;x++){//枚举每个块并预处理
        for(int i=1;i<=tS;i++)
            sums[x][i]=sums[x-1][i];//继承
        for(int i=L[x];i<=R[x];i++){
            if(!rt[x][a[i]])rt[x][a[i]]=i;
            else fa[i]=rt[x][a[i]];//预处理并查集
            cnt[x][a[i]]++,sums[x][bsl(a[i])]++;//累加
        }
        for(int i=1;i<=V;i++)
            sumc[x][i]=sumc[x-1][i]+cnt[x][i];//继承并算和
    }
    while(Q--){//开始处理各个操作！
        int opt=read();
        if(opt==1){//修改操作
            int l=read(),r=read();
            int x=read(),y=read();//读入
            if(x==y)continue;
            if(bel(l)==bel(r))//在同一个块里，只有一个散块
                recon(bel(l),l,r,x,y);//直接调用函数修改
            else{//存在正常的整块
                int lb=bel(l),rb=bel(r);
                recon(lb,l,R[lb],x,y);//左端散块
                recon(rb,L[rb],r,x,y);//右端散块
                int sc=0;//累加当前修改位置个数
                for(int i=lb+1;i<rb;i++){
                    if(rt[i][x]){//有值为 x 的位置
                        if(!rt[i][y])rt[i][y]=rt[i][x],a[rt[i][x]]=y;
                        else fa[rt[i][x]]=rt[i][y];
                        //并查集合并，注意考虑是否有“原住民”
                        rt[i][x]=0;sc+=cnt[i][x];
                        cnt[i][y]+=cnt[i][x],cnt[i][x]=0;
                        //累加位置个数并同步更新 cnt
                    }
                    sumc[i][x]-=sc,sumc[i][y]+=sc;//更新
                    sums[i][bsl(x)]-=sc,sums[i][bsl(y)]+=sc;//更新
                }
                for(int i=rb;i<=tot;i++){
                    sumc[i][x]-=sc,sumc[i][y]+=sc;//更新
                    sums[i][bsl(x)]-=sc,sums[i][bsl(y)]+=sc;//更新
                }
            }
        }else{//查询操作
            int l=read(),r=read(),k=read();//读入
            if(bel(l)==bel(r)){//只存在一个散块
                for(int i=l;i<=r;i++)
                    a[i]=a[FF(i)],tc[a[i]]++,ts[bsl(a[i])]++;
                    //用临时数组存下值域个数情况
                int tmp=0,l0=0,r0=0;
                for(int i=1;i<=tS;i++){
                    tmp+=ts[i];//累加
                    if(tmp>=k){//达到阈值
                        tmp-=ts[i];//减掉防止影响后面判断
                        l0=(i-1)*S+1,r0=i*S;//求出范围
                        break;//打断循环
                    }
                }
                int res=0;
                for(int i=l0;i<=r0;i++){
                    tmp+=tc[i];//累加
                    if(tmp>=k){res=i;break;}//达到了就记录下答案
                }
                for(int i=l;i<=r;i++)
                    tc[a[i]]--,ts[bsl(a[i])]--;//记得清空哦
                cout<<res<<"\n";
            }else{//有完整整块
                int lb=bel(l),rb=bel(r);
                for(int i=l;i<=R[lb];i++)
                    a[i]=a[FF(i)],tc[a[i]]++,ts[bsl(a[i])]++;
                for(int i=L[rb];i<=r;i++)
                    a[i]=a[FF(i)],tc[a[i]]++,ts[bsl(a[i])]++;
                //用临时数组存下两端散块值域个数情况
                int tmp=0,l0=0,r0=0;
                for(int i=1;i<=tS;i++){
                    tmp+=ts[i]+sums[rb-1][i]-sums[lb][i];//累加
                    if(tmp>=k){//达到阈值
                        tmp-=ts[i]+sums[rb-1][i]-sums[lb][i];
                        //减掉防止影响后面判断
                        l0=(i-1)*S+1,r0=i*S;//求出范围
                        break;//打断循环
                    }
                }
                int res=0;
                for(int i=l0;i<=r0;i++){
                    tmp+=tc[i]+sumc[rb-1][i]-sumc[lb][i];//累加
                    if(tmp>=k){res=i;break;}//达到了就记录下答案
                }
                for(int i=l;i<=R[lb];i++)
                    tc[a[i]]--,ts[bsl(a[i])]--;
                for(int i=L[rb];i<=r;i++)
                    tc[a[i]]--,ts[bsl(a[i])]--;
                //记得清空哦
                cout<<res<<"\n";
            }
        }
    }
    return 0;
}
